import os

WEB = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), 'apps', 'web')

def test_next_config_exists():
    assert os.path.exists(os.path.join(WEB, 'next.config.ts'))

def test_tsconfig_exists():
    assert os.path.exists(os.path.join(WEB, 'tsconfig.json'))

def test_package_json_has_next():
    import json
    pkg = json.load(open(os.path.join(WEB, 'package.json')))
    assert 'next' in pkg.get('dependencies', {})

import type { NextConfig } from 'next';
const config: NextConfig = {};
export default config;

const BASE_URL = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000';

async function apiFetch(path: string, options?: RequestInit) {
  const res = await fetch(`${BASE_URL}${path}`, options);
  if (!res.ok) throw new Error(`API error ${res.status}`);
  return res.json();
}

export async function listProjects() {
  return apiFetch('/api/v1/projects');
}

export async function createProject(name: string, type: string) {
  return apiFetch('/api/v1/projects', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-role': 'lawyer' },
    body: JSON.stringify({ name, type }),
  });
}

export async function getDocument(id: number) {
  return apiFetch(`/api/v1/documents/${id}`);
}

export async function exportMd(id: number): Promise<string> {
  const res = await fetch(`${BASE_URL}/api/v1/documents/${id}/export/md`, { method: 'POST' });
  return res.text();
}

