'use client';
import { useEffect, useState } from 'react';
import { listProjects, createProject } from '@/lib/api';

type Project = { id: number; name: string; type: string; status: string };

export default function ProjectsPage() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [name, setName] = useState('');
  const [type, setType] = useState('litigation');

  useEffect(() => {
    listProjects().then(setProjects).catch(console.error);
  }, []);

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    const p = await createProject(name, type);
    setProjects(prev => [...prev, p]);
    setName('');
  }

  return (
    <main style={{ padding: '2rem', fontFamily: 'sans-serif' }}>
      <h1>项目列表</h1>
      <form onSubmit={handleCreate} style={{ marginBottom: '1.5rem', display: 'flex', gap: '0.5rem' }}>
        <input value={name} onChange={e => setName(e.target.value)} placeholder="项目名称" required />
        <select value={type} onChange={e => setType(e.target.value)}>
          <option value="litigation">诉讼</option>
          <option value="consulting">咨询</option>
          <option value="content">内容</option>
        </select>
        <button type="submit">新建</button>
      </form>
      <ul>
        {projects.map(p => (
          <li key={p.id}>{p.name} — {p.type} — {p.status}</li>
        ))}
      </ul>
    </main>
  );
}
